   1→import { getPaperPreset } from '@/sheets/paper';
   2→
   3→const MM_TO_PT = 72 / 25.4;
   4→const ARC_SEGMENTS = 10;
   5→const MM_PER_INCH = 25.4;
   6→const DEFAULT_PNG_DPI = 300;
   7→const JPEG_QUALITY = 0.92;
   8→
   9→function sanitizeFileName(name = 'sheet') {
  10→  return name
  11→    .trim()
  12→    .replace(/[<>:"/\\|?*\x00-\x1F]/g, '-')
  13→    .replace(/\s+/g, ' ')
  14→    .slice(0, 120)
  15→    || 'sheet';
  16→}
