  18→function downloadBlob(blob, fileName) {
  19→  const url = URL.createObjectURL(blob);
  20→  const link = document.createElement('a');
  21→  link.href = url;
  22→  link.download = fileName;
  23→  document.body.appendChild(link);
  24→  link.click();
  25→  link.remove();
  26→  window.setTimeout(() => URL.revokeObjectURL(url), 1000);
  27→}
  28→
  29→function applyComputedSvgStyle(sourceElement, targetElement) {
  30→  const style = window.getComputedStyle(sourceElement);
  31→  const properties = [
  32→    'fill',
  33→    'fill-opacity',
  34→    'stroke',
  35→    'stroke-opacity',
  36→    'stroke-width',
  37→    'stroke-linecap',
  38→    'stroke-linejoin',
  39→    'stroke-dasharray',
  40→    'opacity',
  41→    'font-size',
  42→    'font-family',
  43→    'font-weight',
  44→    'letter-spacing',
  45→    'text-anchor',
  46→    'dominant-baseline',
  47→  ];
  48→
  49→  for (const property of properties) {
  50→    const value = style.getPropertyValue(property);
  51→    if (value) {
  52→      targetElement.style.setProperty(property, value);
  53→    }
  54→  }
  55→}
  56→
  57→function inlineComputedStyles(sourceRoot, clonedRoot) {
  58→  const sourceNodes = [sourceRoot, ...sourceRoot.querySelectorAll('*')];
  59→  const clonedNodes = [clonedRoot, ...clonedRoot.querySelectorAll('*')];
  60→
  61→  for (let index = 0; index < sourceNodes.length; index += 1) {
  62→    applyComputedSvgStyle(sourceNodes[index], clonedNodes[index]);
  63→  }
  64→}
