 276→function parseColor(styleValue) {
 277→  if (!styleValue || styleValue === 'none') return null;
 278→  const normalized = String(styleValue).trim();
 279→
 280→  if (normalized.startsWith('#')) {
 281→    const hex = normalized.slice(1);
 282→    const chunks = hex.length === 3
 283→      ? hex.split('').map((value) => value + value)
 284→      : [hex.slice(0, 2), hex.slice(2, 4), hex.slice(4, 6)];
 285→    return chunks.map((value) => parseInt(value, 16) / 255);
 286→  }
 287→
 288→  const rgb = normalized.match(/rgba?\(([^)]+)\)/i);
 289→  if (rgb) {
 290→    const values = rgb[1].split(',').map((value) => Number.parseFloat(value.trim()));
 291→    return values.slice(0, 3).map((value) => value / 255);
 292→  }
 293→
 294→  return null;
 295→}
 296→
 297→function computeStyle(element) {
 298→  const style = window.getComputedStyle(element);
 299→  const fill = parseColor(style.fill);
 300→  const stroke = parseColor(style.stroke);
 301→  const strokeWidth = Number.parseFloat(style.strokeWidth) || 0;
 302→  const lineCap = style.strokeLinecap || 'butt';
 303→  const lineJoin = style.strokeLinejoin || 'miter';
 304→  const dashArray = parseNumberList(style.strokeDasharray || '');
 305→  const fontSize = Number.parseFloat(style.fontSize) || 12;
 306→  const opacity = Number.parseFloat(style.opacity || '1') || 1;
 307→  const fillOpacity = fill ? opacity * (Number.parseFloat(style.fillOpacity || '1') || 1) : 0;
 308→  const strokeOpacity = stroke ? opacity * (Number.parseFloat(style.strokeOpacity || '1') || 1) : 0;
 309→
 310→  return {
 311→    fill,
 312→    stroke,
 313→    strokeWidth,
 314→    lineCap,
 315→    lineJoin,
 316→    dashArray,
 317→    fontSize,
 318→    fontFamily: style.fontFamily || 'Arial',
 319→    fontWeight: style.fontWeight || '400',
 320→    textAnchor: style.textAnchor || 'start',
 321→    dominantBaseline: style.dominantBaseline || 'auto',
 322→    fillOpacity,
 323→    strokeOpacity,
 324→  };
 325→}
 326→
 327→function lineCapCode(value) {
 328→  if (value === 'round') return 1;
 329→  if (value === 'square') return 2;
 330→  return 0;
 331→}
 332→
 333→function lineJoinCode(value) {
 334→  if (value === 'round') return 1;
 335→  if (value === 'bevel') return 2;
 336→  return 0;
 337→}
