 339→function normalizeSweep(delta, sweepFlag) {
 340→  let result = delta;
 341→  if (sweepFlag && result < 0) result += Math.PI * 2;
 342→  if (!sweepFlag && result > 0) result -= Math.PI * 2;
 343→  return result;
 344→}
 345→
 346→function buildArcPoints(start, rx, ry, rotation, largeArcFlag, sweepFlag, end) {
 347→  if (!start || !end) return [end];
 348→  if (Math.abs(rotation) > 1e-6 || Math.abs(rx - ry) > 1e-6) return [end];
 349→  const radius = Math.abs(rx);
 350→  const dx = end.x - start.x;
 351→  const dy = end.y - start.y;
 352→  const chordLength = Math.hypot(dx, dy);
 353→  if (chordLength < 1e-6 || radius < chordLength / 2) return [end];
 354→
 355→  const midX = (start.x + end.x) / 2;
 356→  const midY = (start.y + end.y) / 2;
 357→  const halfChord = chordLength / 2;
 358→  const offsetLength = Math.sqrt(Math.max(0, radius * radius - halfChord * halfChord));
 359→  const ux = -dy / chordLength;
 360→  const uy = dx / chordLength;
 361→
 362→  const centers = [
 363→    { x: midX + ux * offsetLength, y: midY + uy * offsetLength },
 364→    { x: midX - ux * offsetLength, y: midY - uy * offsetLength },
 365→  ];
 366→
 367→  for (const center of centers) {
 368→    const startAngle = Math.atan2(start.y - center.y, start.x - center.x);
 369→    const endAngle = Math.atan2(end.y - center.y, end.x - center.x);
 370→    const sweepDelta = normalizeSweep(endAngle - startAngle, Boolean(sweepFlag));
 371→    const isLarge = Math.abs(sweepDelta) > Math.PI;
 372→    if (isLarge !== Boolean(largeArcFlag)) continue;
 373→
 374→    const points = [];
 375→    for (let index = 1; index <= ARC_SEGMENTS; index += 1) {
 376→      const angle = startAngle + (sweepDelta * index) / ARC_SEGMENTS;
 377→      points.push({
 378→        x: center.x + radius * Math.cos(angle),
 379→        y: center.y + radius * Math.sin(angle),
 380→      });
 381→    }
 382→    return points;
 383→  }
 384→
 385→  return [end];
 386→}
