 494→class PdfBuilder {
 495→  constructor(pageWidthPt, pageHeightPt) {
 496→    this.pageWidthPt = pageWidthPt;
 497→    this.pageHeightPt = pageHeightPt;
 498→    this.content = [];
 499→    this.alphaMap = new Map();
 500→    this.images = [];
 501→  }
 502→
 503→  write(line) {
 504→    this.content.push(`${line}\n`);
 505→  }
 506→
 507→  alphaName(fillOpacity, strokeOpacity) {
 508→    const fill = Math.max(0, Math.min(1, fillOpacity));
 509→    const stroke = Math.max(0, Math.min(1, strokeOpacity));
 510→    if (fill >= 0.999 && stroke >= 0.999) return null;
 511→    const key = `${fill.toFixed(3)}:${stroke.toFixed(3)}`;
 512→    if (!this.alphaMap.has(key)) {
 513→      this.alphaMap.set(key, {
 514→        name: `GS${this.alphaMap.size + 1}`,
 515→        fill,
 516→        stroke,
 517→      });
 518→    }
 519→    return this.alphaMap.get(key).name;
 520→  }
 521→
 522→  applyStyle(style, { fillAllowed = true, strokeAllowed = true } = {}) {
 523→    if (strokeAllowed && style.stroke && style.strokeWidth > 0) {
 524→      this.write(`${fmt(style.stroke[0])} ${fmt(style.stroke[1])} ${fmt(style.stroke[2])} RG`);
 525→      this.write(`${fmt(style.strokeWidth)} w`);
 526→      this.write(`${lineCapCode(style.lineCap)} J`);
 527→      this.write(`${lineJoinCode(style.lineJoin)} j`);
 528→      if (style.dashArray.length) {
 529→        this.write(`[${style.dashArray.map(fmt).join(' ')}] 0 d`);
 530→      } else {
 531→        this.write('[] 0 d');
 532→      }
 533→    }
 534→
 535→    if (fillAllowed && style.fill) {
 536→      this.write(`${fmt(style.fill[0])} ${fmt(style.fill[1])} ${fmt(style.fill[2])} rg`);
 537→    }
 538→
 539→    const alphaName = this.alphaName(
 540→      fillAllowed ? style.fillOpacity : 1,
 541→      strokeAllowed ? style.strokeOpacity : 1
 542→    );
 543→    if (alphaName) {
 544→      this.write(`/${alphaName} gs`);
 545→    }
 546→  }
 547→
 548→  addImage(jpegBytes, pixelWidth, pixelHeight) {
 549→    const name = `Im${this.images.length + 1}`;
 550→    this.images.push({ name, jpegBytes, pixelWidth, pixelHeight });
 551→    return name;
 552→  }
 553→
 554→  finish() {
 555→    const encoder = new TextEncoder();
 556→    const contentStream = encoder.encode(this.content.join(''));
 557→    const alphaObjects = [...this.alphaMap.values()];
 558→    const fontObjectNumber = 4;
 559→    const firstAlphaObjectNumber = 5;
 560→    const firstImageObjectNumber = firstAlphaObjectNumber + alphaObjects.length;
 561→    const contentObjectNumber = firstImageObjectNumber + this.images.length;
 562→    const totalObjects = contentObjectNumber;
 563→    const objects = [];
 564→
 565→    objects[1] = encoder.encode('1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n');
 566→    objects[2] = encoder.encode('2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n');
 567→
 568→    const extGStateEntries = alphaObjects
 569→      .map((entry, index) => `/${entry.name} ${firstAlphaObjectNumber + index} 0 R`)
 570→      .join(' ');
 571→
 572→    const xObjectEntries = this.images
 573→      .map((entry, index) => `/${entry.name} ${firstImageObjectNumber + index} 0 R`)
 574→      .join(' ');
 575→
 576→    let resources = `/Font << /F1 ${fontObjectNumber} 0 R >>`;
 577→    if (extGStateEntries) resources += ` /ExtGState << ${extGStateEntries} >>`;
 578→    if (xObjectEntries) resources += ` /XObject << ${xObjectEntries} >>`;
 579→
 580→    objects[3] = encoder.encode(
 581→      `3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ${fmt(this.pageWidthPt)} ${fmt(this.pageHeightPt)}] /Resources << ${resources} >> /Contents ${contentObjectNumber} 0 R >>\nendobj\n`
 582→    );
 583→    objects[4] = encoder.encode('4 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n');
 584→
 585→    alphaObjects.forEach((entry, index) => {
 586→      objects[firstAlphaObjectNumber + index] = encoder.encode(
 587→        `${firstAlphaObjectNumber + index} 0 obj\n<< /Type /ExtGState /ca ${fmt(entry.fill)} /CA ${fmt(entry.stroke)} >>\nendobj\n`
 588→      );
 589→    });
 590→
 591→    this.images.forEach((entry, index) => {
 592→      const objNum = firstImageObjectNumber + index;
 593→      const headerBytes = encoder.encode(
 594→        `${objNum} 0 obj\n<< /Type /XObject /Subtype /Image /Width ${entry.pixelWidth} /Height ${entry.pixelHeight} /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${entry.jpegBytes.length} >>\nstream\n`
 595→      );
 596→      const footerBytes = encoder.encode('\nendstream\nendobj\n');
 597→      const combined = new Uint8Array(headerBytes.length + entry.jpegBytes.length + footerBytes.length);
 598→      combined.set(headerBytes, 0);
 599→      combined.set(entry.jpegBytes, headerBytes.length);
 600→      combined.set(footerBytes, headerBytes.length + entry.jpegBytes.length);
 601→      objects[objNum] = combined;
 602→    });
 603→
 604→    const contentHeader = encoder.encode(
 605→      `${contentObjectNumber} 0 obj\n<< /Length ${contentStream.length} >>\nstream\n`
 606→    );
 607→    const contentFooter = encoder.encode('endstream\nendobj\n');
 608→    objects[contentObjectNumber] = new Uint8Array(contentHeader.length + contentStream.length + contentFooter.length);
 609→    objects[contentObjectNumber].set(contentHeader, 0);
 610→    objects[contentObjectNumber].set(contentStream, contentHeader.length);
 611→    objects[contentObjectNumber].set(contentFooter, contentHeader.length + contentStream.length);
 612→
 613→    const header = encoder.encode('%PDF-1.4\n');
 614→    const binaryComment = new Uint8Array([0x25, 0xe2, 0xe3, 0xcf, 0xd3, 0x0a]);
 615→    const offsets = [0];
 616→    let offset = header.length + binaryComment.length;
 617→
 618→    for (let index = 1; index <= totalObjects; index += 1) {
 619→      offsets[index] = offset;
 620→      offset += objects[index].length;
 621→    }
 622→
 623→    const xrefStart = offset;
 624→    let xref = `xref\n0 ${totalObjects + 1}\n0000000000 65535 f \n`;
 625→    for (let index = 1; index <= totalObjects; index += 1) {
 626→      xref += `${String(offsets[index]).padStart(10, '0')} 00000 n \n`;
 627→    }
 628→    const trailer = `trailer\n<< /Size ${totalObjects + 1} /Root 1 0 R >>\nstartxref\n${xrefStart}\n%%EOF`;
 629→
 630→    return new Blob(
 631→      [header, binaryComment, ...objects.slice(1), encoder.encode(xref), encoder.encode(trailer)],
 632→      { type: 'application/pdf' }
 633→    );
 634→  }
 635→}
 636→
 637→function beginNode(builder, element) {
 638→  const localMatrix = getLocalMatrix(element);
 639→  const tagName = element.tagName.toLowerCase();
 640→  const needsClip = tagName === 'svg' && element !== getExportSvg();
 641→  const shouldWrap = needsClip || !matrixIsIdentity(localMatrix);
 642→
 643→  if (!shouldWrap) return false;
 644→
 645→  builder.write('q');
 646→  if (!matrixIsIdentity(localMatrix)) {
 647→    builder.write(`${fmt(localMatrix.a)} ${fmt(localMatrix.b)} ${fmt(localMatrix.c)} ${fmt(localMatrix.d)} ${fmt(localMatrix.e)} ${fmt(localMatrix.f)} cm`);
 648→  }
 649→
 650→  if (needsClip) {
 651→    const width = Number(element.getAttribute('width')) || 0;
 652→    const height = Number(element.getAttribute('height')) || 0;
 653→    builder.write(`0 0 ${fmt(width)} ${fmt(height)} re W n`);
 654→  }
 655→
 656→  return true;
 657→}
 658→
 659→function endNode(builder, wrapped) {
 660→  if (wrapped) {
 661→    builder.write('Q');
 662→  }
 663→}
 664→
 665→function beginCanvasNode(context, element) {
 666→  const localMatrix = getLocalMatrix(element);
 667→  const tagName = element.tagName.toLowerCase();
 668→  const needsClip = tagName === 'svg' && element !== getExportSvg();
 669→
 670→  context.save();
 671→  if (!matrixIsIdentity(localMatrix)) {
 672→    context.transform(
 673→      localMatrix.a,
 674→      localMatrix.b,
 675→      localMatrix.c,
 676→      localMatrix.d,
 677→      localMatrix.e,
 678→      localMatrix.f
 679→    );
 680→  }
 681→
 682→  if (needsClip) {
 683→    const width = Number(element.getAttribute('width')) || 0;
 684→    const height = Number(element.getAttribute('height')) || 0;
 685→    context.beginPath();
 686→    context.rect(0, 0, width, height);
 687→    context.clip();
 688→  }
 689→}
 690→
 691→function endCanvasNode(context) {
 692→  context.restore();
 693→}
 694→
 695→function applyCanvasStyle(context, style) {
 696→  if (style.fill) {
 697→    context.fillStyle = `rgb(${Math.round(style.fill[0] * 255)}, ${Math.round(style.fill[1] * 255)}, ${Math.round(style.fill[2] * 255)})`;
 698→  }
 699→  if (style.stroke && style.strokeWidth > 0) {
 700→    context.strokeStyle = `rgb(${Math.round(style.stroke[0] * 255)}, ${Math.round(style.stroke[1] * 255)}, ${Math.round(style.stroke[2] * 255)})`;
 701→    context.lineWidth = style.strokeWidth;
 702→    context.lineCap = style.lineCap || 'butt';
 703→    context.lineJoin = style.lineJoin || 'miter';
 704→    context.setLineDash(style.dashArray || []);
 705→  } else {
 706→    context.setLineDash([]);
 707→  }
 708→}
 709→
 710→function fillAndStrokeCanvasPath(context, style) {
 711→  const hasFill = Boolean(style.fill);
 712→  const hasStroke = Boolean(style.stroke && style.strokeWidth > 0);
 713→
 714→  if (hasFill) {
 715→    context.globalAlpha = style.fillOpacity;
 716→    context.fill();
 717→  }
 718→  if (hasStroke) {
 719→    context.globalAlpha = style.strokeOpacity;
 720→    context.stroke();
 721→  }
 722→  context.globalAlpha = 1;
 723→}
 724→
 725→function drawRectToCanvas(context, element) {
 726→  const style = computeStyle(element);
 727→  const x = Number(element.getAttribute('x')) || 0;
 728→  const y = Number(element.getAttribute('y')) || 0;
 729→  const width = Number(element.getAttribute('width')) || 0;
 730→  const height = Number(element.getAttribute('height')) || 0;
 731→
 732→  context.save();
 733→  applyCanvasStyle(context, style);
 734→  context.beginPath();
 735→  context.rect(x, y, width, height);
 736→  fillAndStrokeCanvasPath(context, style);
 737→  context.restore();
 738→}
 739→
 740→function drawLineToCanvas(context, element) {
 741→  const style = computeStyle(element);
 742→  if (!style.stroke || style.strokeWidth <= 0) return;
 743→
 744→  context.save();
 745→  applyCanvasStyle(context, style);
 746→  context.globalAlpha = style.strokeOpacity;
 747→  context.beginPath();
 748→  context.moveTo(Number(element.getAttribute('x1')) || 0, Number(element.getAttribute('y1')) || 0);
 749→  context.lineTo(Number(element.getAttribute('x2')) || 0, Number(element.getAttribute('y2')) || 0);
 750→  context.stroke();
 751→  context.restore();
 752→}
 753→
 754→function drawPolygonToCanvas(context, element, closePath) {
 755→  const style = computeStyle(element);
 756→  const points = parsePoints(element.getAttribute('points') || '');
 757→  if (!points.length) return;
 758→
 759→  context.save();
 760→  applyCanvasStyle(context, style);
 761→  context.beginPath();
 762→  context.moveTo(points[0].x, points[0].y);
 763→  for (let index = 1; index < points.length; index += 1) {
 764→    context.lineTo(points[index].x, points[index].y);
 765→  }
 766→  if (closePath) context.closePath();
 767→  fillAndStrokeCanvasPath(context, style);
 768→  context.restore();
 769→}
 770→
 771→function drawPathToCanvas(context, element) {
 772→  const style = computeStyle(element);
 773→  const commands = parsePathData(element.getAttribute('d') || '');
 774→  if (!commands.length) return;
 775→
 776→  context.save();
 777→  applyCanvasStyle(context, style);
 778→  context.beginPath();
 779→  for (const command of commands) {
 780→    if (command.type === 'M') context.moveTo(command.x, command.y);
 781→    else if (command.type === 'L') context.lineTo(command.x, command.y);
 782→    else if (command.type === 'Z') context.closePath();
 783→  }
 784→  fillAndStrokeCanvasPath(context, style);
 785→  context.restore();
 786→}
 787→
 788→function drawTextToCanvas(context, element) {
 789→  const style = computeStyle(element);
 790→  if (!style.fill) return;
 791→
 792→  context.save();
 793→  context.fillStyle = `rgb(${Math.round(style.fill[0] * 255)}, ${Math.round(style.fill[1] * 255)}, ${Math.round(style.fill[2] * 255)})`;
 794→  context.globalAlpha = style.fillOpacity;
 795→  context.font = `${style.fontWeight} ${style.fontSize}px ${style.fontFamily}`;
 796→  context.textAlign = style.textAnchor === 'middle' ? 'center' : style.textAnchor === 'end' ? 'right' : 'left';
 797→  context.textBaseline = style.dominantBaseline === 'middle' ? 'middle' : 'alphabetic';
 798→
 799→  const lines = getTextLines(element);
 800→  for (const line of lines) {
 801→    context.fillText(line.text, line.x, line.y);
 802→  }
 803→
 804→  context.restore();
 805→}
 806→
 807→function drawImageToCanvas(context, element, imageMap) {
 808→  const href = element.getAttribute('href') || element.getAttributeNS('http://www.w3.org/1999/xlink', 'href');
 809→  const entry = href && imageMap.get(href);
 810→  if (!entry) return;
 811→  const x = Number(element.getAttribute('x')) || 0;
 812→  const y = Number(element.getAttribute('y')) || 0;
 813→  const width = Number(element.getAttribute('width')) || entry.width;
 814→  const height = Number(element.getAttribute('height')) || entry.height;
 815→  context.drawImage(entry.img, x, y, width, height);
 816→}
 817→
 818→function drawElementToCanvas(context, element, imageMap) {
 819→  const tagName = element.tagName.toLowerCase();
 820→  beginCanvasNode(context, element);
 821→
 822→  switch (tagName) {
 823→    case 'svg':
 824→    case 'g':
 825→      [...element.children].forEach((child) => drawElementToCanvas(context, child, imageMap));
 826→      break;
 827→    case 'rect':
 828→      drawRectToCanvas(context, element);
 829→      break;
 830→    case 'line':
 831→      drawLineToCanvas(context, element);
 832→      break;
 833→    case 'polygon':
 834→      drawPolygonToCanvas(context, element, true);
 835→      break;
 836→    case 'polyline':
 837→      drawPolygonToCanvas(context, element, false);
 838→      break;
 839→    case 'path':
 840→      drawPathToCanvas(context, element);
 841→      break;
 842→    case 'text':
 843→      drawTextToCanvas(context, element);
 844→      break;
 845→    case 'image':
 846→      drawImageToCanvas(context, element, imageMap);
 847→      break;
 848→    default:
 849→      [...element.children].forEach((child) => drawElementToCanvas(context, child, imageMap));
 850→      break;
 851→  }
 852→
 853→  endCanvasNode(context);
 854→}
