186→function clonePoint(point) {
187→  return point ? { x: point.x, y: point.y } : point;
188→}
189→
190→function isFiniteNumber(value) {
191→  return Number.isFinite(value);
192→}
193→
194→function cloneWebPattern(webPattern = {}) {
195→  return {
196→    key: webPattern.key ?? 'generic',
197→    label: webPattern.label ?? 'Generic',
198→    panelCount: Math.max(2, Math.round(webPattern.panelCount ?? 4)),
199→    diagonalMode: webPattern.diagonalMode ?? 'generic',
200→  };
201→}
202→
203→function normalizeFamily(family = 'gable') {
204→  if (family === 'mono') return 'shed';
205→  return TRUSS_FAMILIES.has(family) ? family : 'gable';
206→}
207→
208→function normalizeShape(shape = null, family = 'gable') {
209→  if (shape === 'mono') return 'shed';
210→  if (TRUSS_SHAPES.has(shape)) return shape;
211→  return normalizeFamily(family);
212→}
213→
214→function normalizeAttachedRoofType(attachedRoofType = null) {
215→  if (attachedRoofType == null || attachedRoofType === '') return null;
216→  return TRUSS_ATTACHED_ROOF_TYPES.has(attachedRoofType) ? attachedRoofType : null;
217→}
218→
219→function normalizeSupportMode(supportMode = null) {
220→  return supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR ? supportMode : null;
221→}
222→
223→function normalizeSupportBeamIds(supportBeamIds = {}) {
224→  return {
225→    start: typeof supportBeamIds?.start === 'string' && supportBeamIds.start ? supportBeamIds.start : null,
226→    end: typeof supportBeamIds?.end === 'string' && supportBeamIds.end ? supportBeamIds.end : null,
227→  };
228→}
229→
230→function normalizeSupportOffsetAlongAxis(value = 0) {
231→  return isFiniteNumber(value) ? Math.max(0, value) : 0;
232→}
233→
234→function clonePlanOffset(offset = null) {
235→  return normalizePlanOffset(offset);
236→}
