238→export function normalizeTrussMaterial(material = DEFAULT_TRUSS_MATERIAL) {
239→  const normalized = typeof material === 'string' ? material.trim().toLowerCase() : DEFAULT_TRUSS_MATERIAL;
240→  if (normalized === 'wood') return 'timber';
241→  if (normalized === 'steel' || normalized === 'meta') return 'metal';
242→  return TRUSS_MATERIALS.includes(normalized) ? normalized : DEFAULT_TRUSS_MATERIAL;
243→}
