245→export function createPurlinSystem(options = {}) {
246→  return {
247→    enabled: Boolean(options.enabled),
248→    spacing: isFiniteNumber(options.spacing) ? Math.max(100, options.spacing) : DEFAULT_PURLIN_SPACING,
249→    startOffset: isFiniteNumber(options.startOffset) ? Math.max(0, options.startOffset) : DEFAULT_PURLIN_START_OFFSET,
250→    endOffset: isFiniteNumber(options.endOffset) ? Math.max(0, options.endOffset) : DEFAULT_PURLIN_END_OFFSET,
251→    overhangStart: isFiniteNumber(options.overhangStart) ? Math.max(0, options.overhangStart) : DEFAULT_PURLIN_OVERHANG_START,
252→    overhangEnd: isFiniteNumber(options.overhangEnd) ? Math.max(0, options.overhangEnd) : DEFAULT_PURLIN_OVERHANG_END,
253→    width: isFiniteNumber(options.width) ? Math.max(25, options.width) : DEFAULT_PURLIN_WIDTH,
254→    depth: isFiniteNumber(options.depth) ? Math.max(25, options.depth) : DEFAULT_PURLIN_DEPTH,
255→    material: normalizeTrussMaterial(options.material ?? DEFAULT_PURLIN_MATERIAL),
256→  };
257→}
258→
259→function normalizePurlinSystem(purlinSystem = {}) {
260→  return createPurlinSystem(purlinSystem);
261→}
