290→    defaultRise: isFiniteNumber(options.defaultRise) ? Math.max(0, options.defaultRise) : DEFAULT_RISE,
291→    defaultPitch: isFiniteNumber(options.defaultPitch) ? Math.max(0, options.defaultPitch) : DEFAULT_PITCH,
292→    attachedRoofType: normalizeAttachedRoofType(options.attachedRoofType),
