438→      ? trussSystem.baseElevation
439→      : (floor ? getFloorTopElevation(floor) : 0),
440→    planRotationOffsetDegrees: normalizeRotationDegrees(trussSystem?.planRotationOffsetDegrees),
441→    planOffset: clonePlanOffset(trussSystem?.planOffset),
442→    planLengthScale: normalizePlanLengthScale(trussSystem?.planLengthScale),
