474→export function detachBeamSupportedTrussInstances(trussInstances = []) {
475→  return trussInstances.map((instance) => (
476→    instance.supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR
477→      ? {
478→          ...instance,
479→          supportMode: null,
480→          supportBeamIds: { start: null, end: null },
481→          supportOffsetAlongAxis: 0,
482→        }
