513→function syncTrussSystemGeometry(trussSystem, project, catalog) {
514→  const normalizedSystem = normalizeTrussSystem(trussSystem, project, catalog);
515→  const floor = getProjectFloor(project, normalizedSystem.floorId);
516→  if (!floor) return null;
517→
518→  const roofAttachmentId = project?.roofSystem?.trussAttachmentId === normalizedSystem.id
519→    ? project.roofSystem.id
520→    : null;
521→  const syncedInstances = (normalizedSystem.trussInstances || [])
522→    .map((instance) => syncBeamSupportedInstance(instance, floor, catalog, roofAttachmentId))
523→    .filter(Boolean);
524→
525→  if (!syncedInstances.length) {
526→    return null;
527→  }
528→
529→  const beamSupportedInstance = syncedInstances.find((instance) => (
530→    instance.supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR
531→  )) || null;
532→  const derivedBaseElevation = beamSupportedInstance
533→    ? deriveBeamSupportedInstanceGeometry(beamSupportedInstance, floor)
534→    : null;
535→
536→  return {
537→    ...normalizedSystem,
538→    baseElevation: derivedBaseElevation?.valid
539→      ? derivedBaseElevation.baseElevation
540→      : normalizedSystem.baseElevation,
541→    trussInstances: syncedInstances,
542→  };
543→}
