545→export function syncProjectTrussSystems(project) {
546→  if (!project) return project;
547→
548→  const catalog = getDefaultTrussTypes();
549→  const normalizedTrussSystems = (project.trussSystems || [])
550→    .map((trussSystem) => syncTrussSystemGeometry(trussSystem, project, catalog))
551→    .filter(Boolean);
552→
553→  const validTrussIds = new Set(normalizedTrussSystems.map((entry) => entry.id));
554→  const roofSystem = project.roofSystem && project.roofSystem.trussAttachmentId && !validTrussIds.has(project.roofSystem.trussAttachmentId)
555→    ? {
556→        ...project.roofSystem,
557→        trussAttachmentId: null,
558→      }
559→    : project.roofSystem;
560→
561→  return {
562→    ...project,
563→    version: Math.max(CURRENT_PROJECT_VERSION, Number(project.version || 0)),
564→    roofSystem,
565→    trussSystems: normalizedTrussSystems,
566→  };
567→}
