106→function normalizeAttachedShapeProfile(shapeProfile = null, roofType = null) {
107→  const points = (shapeProfile?.points || [])
108→    .map((point) => ({
109→      position: Math.max(0, Math.min(1, Number(point?.position) || 0)),
110→      rise: Math.max(0, Number(point?.rise) || 0),
111→    }))
112→    .filter((point) => Number.isFinite(point.position) && Number.isFinite(point.rise))
113→    .sort((a, b) => a.position - b.position);
114→
115→  if (points.length < 2) return null;
116→
117→  return {
118→    shape: normalizeRoofType(shapeProfile?.shape ?? roofType ?? 'flat'),
119→    totalSpan: Math.max(0, Number(shapeProfile?.totalSpan) || 0),
120→    maxRise: Math.max(0, Number(shapeProfile?.maxRise) || Math.max(...points.map((point) => point.rise))),
121→    points,
122→  };
