160→function resolveAttachedRoofOverrides(roofSystemLike, attachmentContext) {
161→  const derivedRoofState = attachmentContext?.derivedRoofState || null;
162→  const followsAttachedTruss = Boolean(roofSystemLike?.trussAttachmentId && derivedRoofState);
163→  const roofType = followsAttachedTruss
164→    ? normalizeRoofType(derivedRoofState.roofType)
165→    : normalizeRoofType(roofSystemLike?.roofType ?? 'flat');
166→  const pitchSource = normalizeRoofPitchSource(roofSystemLike?.pitchSource, roofSystemLike?.trussAttachmentId);
167→  const allowsManualAttachedSlope = followsAttachedTruss && roofType !== 'flat' && roofType !== 'custom';
168→  const attachedPitch = followsAttachedTruss
169→    ? {
170→        ...derivedRoofState.pitch,
171→        overhang: isFiniteNumber(roofSystemLike?.pitch?.overhang)
172→          ? Math.max(0, roofSystemLike.pitch.overhang)
173→          : (derivedRoofState.pitch?.overhang ?? 0),
174→      }
175→    : null;
176→  const pitch = followsAttachedTruss
177→    ? createRoofPitch(
178→        allowsManualAttachedSlope && pitchSource === 'manual'
179→          ? {
180→              ...attachedPitch,
181→              slope: isFiniteNumber(roofSystemLike?.pitch?.slope)
