183→                : derivedRoofState.pitch?.slope,
184→            }
185→          : attachedPitch
186→      )
187→    : createRoofPitch(roofSystemLike?.pitch);
188→  const boundaryPolygon = followsAttachedTruss
189→    ? clonePoints(attachmentContext?.derivedBoundaryPolygon || [])
190→    : clonePoints(roofSystemLike?.boundaryPolygon || createDefaultBoundary());
191→
192→  return {
193→    followsAttachedTruss,
194→    pitchSource: allowsManualAttachedSlope ? pitchSource : 'manual',
