236→function boundsToPolygon(points = []) {
237→  if (points.length < 3) return createDefaultBoundary();
238→
239→  const minX = Math.min(...points.map((point) => point.x));
240→  const maxX = Math.max(...points.map((point) => point.x));
241→  const minY = Math.min(...points.map((point) => point.y));
242→  const maxY = Math.max(...points.map((point) => point.y));
243→
244→  if (!isFiniteNumber(minX) || !isFiniteNumber(maxX) || !isFiniteNumber(minY) || !isFiniteNumber(maxY)) {
245→    return createDefaultBoundary();
246→  }
247→
248→  const width = Math.max(1000, maxX - minX);
249→  const height = Math.max(1000, maxY - minY);
250→  const insetX = width < 1000 ? (1000 - width) / 2 : 0;
251→  const insetY = height < 1000 ? (1000 - height) / 2 : 0;
252→
253→  return [
254→    { x: minX - insetX, y: minY - insetY },
255→    { x: maxX + insetX, y: minY - insetY },
256→    { x: maxX + insetX, y: maxY + insetY },
257→    { x: minX - insetX, y: maxY + insetY },
258→  ];
259→}
