629→export function createRoofSystemForProject(project, options = {}) {
630→  const resolvedTrussAttachmentId = resolveCreateRoofAttachmentId(project, options.trussAttachmentId, options.catalog);
631→  if (!resolvedTrussAttachmentId) {
632→    return null;
633→  }
634→
635→  const creationOptions = {
636→    ...options,
637→    trussAttachmentId: resolvedTrussAttachmentId,
638→  };
639→  const attachmentContext = resolveRoofAttachmentContext(project, creationOptions, options.catalog);
640→  const attachmentElevation = attachmentContext.attachmentElevation;
641→  const attachmentOffset = isFiniteNumber(options.attachmentOffset)
642→    ? options.attachmentOffset
643→    : 0;
644→  const attachedOverrides = resolveAttachedRoofOverrides(creationOptions, attachmentContext);
645→  if (!attachedOverrides.followsAttachedTruss) return null;
646→
647→  return createRoofSystem(options.name ?? 'Roof', {
648→    ...creationOptions,
649→    baseElevation: options.baseElevation ?? (attachmentElevation + attachmentOffset),
650→    attachmentOffset,
651→    roofType: attachedOverrides.roofType,
652→    pitch: attachedOverrides.pitch,
653→    attachedShapeProfile: attachedOverrides.attachedShapeProfile,
654→    boundaryPolygon: attachedOverrides.boundaryPolygon,
