663→export function syncRoofSystemAttachment(project, roofSystem) {
664→  if (!roofSystem) return null;
665→
666→  const attachmentContext = resolveRoofAttachmentContext(project, roofSystem);
667→  const attachmentElevation = attachmentContext.attachmentElevation;
668→  const attachedOverrides = resolveAttachedRoofOverrides(roofSystem, attachmentContext);
669→  const attachmentOffset = isFiniteNumber(roofSystem.attachmentOffset)
670→    ? roofSystem.attachmentOffset
671→    : ((roofSystem.baseElevation ?? attachmentElevation) - attachmentElevation);
672→  const normalizedBaseElevation = attachmentElevation + attachmentOffset;
673→  const normalizedRoofType = attachedOverrides.roofType;
674→  const normalizedPitch = attachedOverrides.pitch;
675→  const normalizedBoundaryPolygon = attachedOverrides.boundaryPolygon;
676→  const baseRoofSystem = {
677→    ...roofSystem,
678→    id: roofSystem.id || generateId('roof'),
679→    roofType: normalizedRoofType,
680→    phaseId: normalizePhaseId(roofSystem.phaseId),
681→    trussAttachmentId: normalizeTrussAttachmentId(roofSystem.trussAttachmentId),
682→    pitchSource: attachedOverrides.pitchSource,
683→    attachedShapeProfile: attachedOverrides.attachedShapeProfile,
684→    attachmentOffset,
685→    baseElevation: normalizedBaseElevation,
686→    boundaryPolygon: normalizedBoundaryPolygon,
687→    slabThickness: roofSystem.slabThickness ?? ROOF_SLAB_THICKNESS,
688→    finishSlope: roofSystem.finishSlope ?? ROOF_FINISH_SLOPE,
689→    pitch: normalizedPitch,
690→    parapets: normalizeParapets(roofSystem.parapets || []),
691→    drains: normalizeDrains(roofSystem.drains || []),
692→    roofOpenings: normalizeRoofOpenings(roofSystem.roofOpenings || []),
693→    roofPlanes: normalizeRoofPlanes(
694→      roofSystem.roofPlanes || [],
695→      normalizedRoofType,
696→      normalizedBoundaryPolygon,
697→      normalizedBaseElevation
698→    ),
699→    roofEdges: normalizeRoofEdges(roofSystem.roofEdges || []),
700→    ridges: normalizeRelationships(roofSystem.ridges || [], createRidge),
701→    valleys: normalizeRelationships(roofSystem.valleys || [], createValley),
702→    hips: normalizeRelationships(roofSystem.hips || [], createHip),
703→  };
704→
705→  return {
706→    ...baseRoofSystem,
707→    ...normalizeRoofSystemCollections(baseRoofSystem),
708→  };
709→}
