711→export function syncProjectRoofSystem(project) {
712→  if (!project) return project;
713→
714→  const syncedRoofSystem = project.roofSystem
715→    ? syncRoofSystemAttachment(project, project.roofSystem)
716→    : null;
717→
718→  return {
719→    ...project,
720→    version: Math.max(CURRENT_PROJECT_VERSION, Number(project.version || 0)),
721→    roofSystem: syncedRoofSystem,
722→  };
723→}
