 15→function createShape(outline, holes = []) {
 16→  const shape = new THREE.Shape();
 17→  outline.forEach((point, index) => {
 18→    if (index === 0) {
 19→      // Flip plan Y here so the rotated extrusion preserves the blueprint's handedness.
 20→      shape.moveTo(point.x, -point.y);
 21→      return;
 22→    }
 23→    shape.lineTo(point.x, -point.y);
 24→  });
 25→  shape.closePath();
 26→
 27→  holes.forEach((hole) => {
 28→    if (!hole?.length) return;
 29→    const path = new THREE.Path();
 30→    hole.forEach((point, index) => {
 31→      if (index === 0) {
 32→        path.moveTo(point.x, -point.y);
 33→        return;
 34→      }
 35→      path.lineTo(point.x, -point.y);
 36→    });
 37→    path.closePath();
 38→    shape.holes.push(path);
 39→  });
 40→
 41→  return shape;
