 72→function addOutline(object3d, materialPalette, isSelected) {
 73→  if (!object3d.geometry) return;
 74→  const edges = new THREE.EdgesGeometry(object3d.geometry, 20);
 75→  const outline = new THREE.LineSegments(edges, createOutlineMaterial(materialPalette, isSelected));
 76→  object3d.add(outline);
 77→}
