 3→export const PHASE_VIEW = {
 4→  ALL: 'all',
 5→  SINGLE: 'single',
 6→  CUMULATIVE: 'cumulative',
 7→};
 8→
 9→export function isObjectVisibleInPhase(obj, phases, activePhaseId, phaseViewMode) {
10→  if (obj.phaseId) {
11→    const objPhase = phases.find(p => p.id === obj.phaseId);
12→    if (objPhase && objPhase.visible === false) return false;
13→  }
14→  if (phaseViewMode === PHASE_VIEW.ALL) return true;
15→  if (!obj.phaseId) return true;
16→  if (!activePhaseId) return true;
17→
18→  if (phaseViewMode === PHASE_VIEW.SINGLE) {
19→    return obj.phaseId === activePhaseId;
20→  }
21→
22→  if (phaseViewMode === PHASE_VIEW.CUMULATIVE) {
23→    const activePhase = phases.find(p => p.id === activePhaseId);
24→    const objPhase = phases.find(p => p.id === obj.phaseId);
25→    if (!activePhase || !objPhase) return true;
26→    return objPhase.order <= activePhase.order;
27→  }
28→
29→  return true;
30→}
31→
32→export function filterFloorByPhase(floor, phases, activePhaseId, phaseViewMode) {
33→  if (!floor) return floor;
34→  const hasHiddenPhases = phases.some(p => p.visible === false);
35→  if (phaseViewMode === PHASE_VIEW.ALL && !hasHiddenPhases) return floor;
36→  if (!activePhaseId && !hasHiddenPhases) return floor;
37→
38→  const isVisible = (obj) => isObjectVisibleInPhase(obj, phases, activePhaseId, phaseViewMode);
39→
40→  const filtered = { ...floor };
41→
42→  for (const key of PHASE_ASSIGNABLE_KEYS) {
43→    const arr = floor[key];
44→    if (!arr) continue;
45→    filtered[key] = arr.filter(isVisible);
46→  }
47→
48→  // Also filter doors/windows whose parent wall was filtered out
49→  const visibleWallIds = new Set((filtered.walls || []).map((wall) => wall.id));
50→  filtered.doors = (filtered.doors || []).filter((door) => visibleWallIds.has(door.wallId));
51→  filtered.windows = (filtered.windows || []).filter((windowItem) => visibleWallIds.has(windowItem.wallId));
52→
53→  return filtered;
54→}
