56→export function filterProjectByPhase(project, activePhaseId, phaseViewMode) {
57→  if (!project) return project;
58→  const phases = project.phases || [];
59→  const hasHiddenPhases = phases.some(p => p.visible === false);
60→  if (phaseViewMode === PHASE_VIEW.ALL && !hasHiddenPhases) return project;
61→  if (!activePhaseId && !hasHiddenPhases) return project;
62→
63→  const roofSystem = project.roofSystem && isObjectVisibleInPhase(
64→    project.roofSystem,
65→    phases,
66→    activePhaseId,
67→    phaseViewMode
68→  )
69→    ? project.roofSystem
70→    : null;
71→  const trussSystems = (project.trussSystems || []).filter((trussSystem) => (
72→    isObjectVisibleInPhase(trussSystem, phases, activePhaseId, phaseViewMode)
73→  ));
74→
75→  return {
76→    ...project,
77→    floors: project.floors.map(floor => filterFloorByPhase(floor, phases, activePhaseId, phaseViewMode)),
78→    roofSystem,
79→    trussSystems,
80→  };
81→}
