404→export function resolveSheetViewportSource(project, viewport, phaseContext) {
405→  const defaultFloorId = getDefaultActiveFloorId(project, viewport.sourceFloorId);
406→  let effectiveProject = project;
407→  let floor = resolveProjectFloor(project, defaultFloorId);
408→
409→  if (phaseContext?.activePhaseId && phaseContext?.phaseViewMode && phaseContext.phaseViewMode !== 'all') {
410→    effectiveProject = filterProjectByPhase(project, phaseContext.activePhaseId, phaseContext.phaseViewMode);
411→    floor = resolveProjectFloor(effectiveProject, defaultFloorId);
412→  }
413→
414→  switch (viewport.sourceView) {
415→    case 'truss_plan':
416→      return buildTrussPlanSource(effectiveProject, defaultFloorId);
417→    case 'truss_detail':
418→      return buildTrussDetailSource(effectiveProject, defaultFloorId, viewport.sourceRefId);
419→    case 'roof_plan':
420→      return buildRoofPlanSource(effectiveProject);
421→    case 'roof_drainage':
422→      return buildRoofDrainageSource(effectiveProject);
423→    case 'roof_elevation_front':
424→    case 'roof_elevation_rear':
425→    case 'roof_elevation_left':
426→    case 'roof_elevation_right':
427→      return buildRoofElevationSource(effectiveProject, viewport.sourceView);
428→    case 'roof_section':
429→      return buildRoofSectionSource(effectiveProject, defaultFloorId, viewport.sourceRefId);
430→    case 'roof_schedule':
431→      return buildRoofScheduleSource(effectiveProject);
432→    case '3d_preview':
433→      return build3DPreviewSource(effectiveProject, floor);
434→    case 'section':
435→      return buildSectionSource(effectiveProject, floor, viewport.sourceRefId);
436→    case 'elevation_front':
437→    case 'elevation_rear':
438→    case 'elevation_left':
439→    case 'elevation_right':
440→      return buildElevationSource(effectiveProject, floor, viewport.sourceView);
441→    case 'plan':
442→    default:
443→      return buildPlanSource(floor);
444→  }
445→}
